import "./toggle-group.css";

import { ToggleGroup } from "radix-ui";
import { cn } from "tailwind-variants";

import { ToggleGroupContext } from "./toggle-group.context";
import { toggleGroupVariants } from "./toggle-group.variants";

export type ToggleGroupRootProps = React.ComponentProps<typeof ToggleGroup.Root>;

export const ToggleGroupRoot = ({ className, ...props }: ToggleGroupRootProps) => {
  const slots = toggleGroupVariants();

  return (
    <ToggleGroupContext value={{ slots }}>
      <ToggleGroup.Root className={cn(slots.root(), className)} {...props} />
    </ToggleGroupContext>
  );
};

import { ToggleGroup } from "radix-ui";
import { cn } from "tailwind-variants";

import { useToggleGroupContext } from "./toggle-group.context";

export type ToggleGroupItemProps = React.ComponentProps<typeof ToggleGroup.Item>;

export const ToggleGroupItem = ({ className, ...props }: ToggleGroupItemProps) => {
  const { slots } = useToggleGroupContext();

  return <ToggleGroup.Item className={cn(slots.item(), className)} {...props} />;
};

import { createContext, useContext } from "react";

import { toggleGroupVariants } from "./toggle-group.variants";

export type ToggleGroupContext = {
  slots: ReturnType<typeof toggleGroupVariants>;
};

export const ToggleGroupContext = createContext<null | ToggleGroupContext>(null);

export const useToggleGroupContext = () => {
  const context = useContext(ToggleGroupContext);
  if (!context) {
    throw new Error("useToggleGroupContext must be used within a ToggleGroup");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const toggleGroupVariants = tv({
  slots: {
    item: "toggle-group__item",
    root: "toggle-group",
  },
});

export type ToggleGroupVariants = VariantProps<typeof toggleGroupVariants>;

.toggle-group {
  @apply inline-flex items-center justify-center rounded-md;
}

.toggle-group__item {
  @apply inline-flex size-9 items-center justify-center rounded-md text-sm font-medium transition-colors;

  &:hover {
    @apply bg-muted text-muted-foreground;
  }

  &:focus-visible {
    @apply outline-ring z-10 outline-2 outline-offset-2;
  }

  &:disabled {
    @apply pointer-events-none opacity-50;
  }

  &[data-state="on"] {
    @apply bg-accent text-accent-foreground;
  }
}

import { ToggleGroupItem } from "./toggle-group-item";
import { ToggleGroupRoot } from "./toggle-group-root";

export const ToggleGroup = {
  Item: ToggleGroupItem,
  Root: ToggleGroupRoot,
};

export { ToggleGroupItem, ToggleGroupRoot };

export type { ToggleGroupItemProps } from "./toggle-group-item";

export type { ToggleGroupRootProps } from "./toggle-group-root";

export { ToggleGroupContext, useToggleGroupContext } from "./toggle-group.context";
export { type ToggleGroupVariants, toggleGroupVariants } from "./toggle-group.variants";
